    this.conditionalErrListener = conditionalErrListener;
    try {
        inputs = setupInputs(cve);
        filters = setupFilters(cve);
        outputs = setupOutputs(cve);
    } catch (Exception e) {
        throw new IllegalStateException("Unable to configure plugins: " + e.getMessage(), e);
    }
